import{m as t,aU as a,z as l,M as r}from"./chunks/framework.LN92DB6A.js";const o=JSON.parse('{"title":"广州住房公积金提取最全攻略：租房、买房、离职都能提","description":"在广州交了公积金不知道怎么取？本文整理租房提取、购房提取、离职提取等全场景操作指南，附线上办理全流程。","frontmatter":{"title":"广州住房公积金提取最全攻略：租房、买房、离职都能提","tags":["广州","公积金","公积金提取","租房提取","买房"],"categories":["住房"],"date":"2026-05-28T00:00:00.000Z","description":"在广州交了公积金不知道怎么取？本文整理租房提取、购房提取、离职提取等全场景操作指南，附线上办理全流程。","head":[["link",{"rel":"canonical","href":"https://guangzhou.suporka.site/posts/2026/gzfund-extract"}]]},"headers":[],"relativePath":"posts/2026/gzfund-extract.md","filePath":"posts/2026/gzfund-extract.md","lastUpdated":1779868425000}');const i=t({name:"posts/2026/gzfund-extract.md"},[["render",function(t,o,i,e,n,s){return a(),l("div",null,[...o[0]||(o[0]=[r('<p>在广州工作，公积金每个月都在扣，但很多人交了好几年都不知道怎么提出来。其实提取场景比你想的多——租房、买房、离职、退休，甚至大病都能提。</p><p>今天就把广州公积金提取的几种常见情况整理清楚，照着操作就行。</p><h2 id="哪些情况可以提取" tabindex="-1">哪些情况可以提取 <a class="header-anchor" href="#哪些情况可以提取" aria-label="Permalink to &quot;哪些情况可以提取&quot;">​</a></h2><div class="table-container"><table><thead><tr><th>提取场景</th><th>常见程度</th><th>是否需要材料</th></tr></thead><tbody><tr><td>租房提取</td><td>最常见</td><td>无房证明</td></tr><tr><td>购房提取</td><td>较常见</td><td>购房合同/发票</td></tr><tr><td>离职/离开广州</td><td>常见</td><td>账户封存证明</td></tr><tr><td>退休提取</td><td>一次性</td><td>退休证</td></tr><tr><td>大病提取</td><td>少见</td><td>医院诊断证明</td></tr><tr><td>出境定居</td><td>少见</td><td>出境证明</td></tr></tbody></table></div><h2 id="场景一-租房提取-最常用" tabindex="-1">场景一：租房提取（最常用） <a class="header-anchor" href="#场景一-租房提取-最常用" aria-label="Permalink to &quot;场景一：租房提取（最常用）&quot;">​</a></h2><p>在广州租房住、没有自有住房的职工，可以按月提取公积金用于支付房租。</p><h3 id="申请条件" tabindex="-1">申请条件 <a class="header-anchor" href="#申请条件" aria-label="Permalink to &quot;申请条件&quot;">​</a></h3><ul><li>职工及配偶在广州<strong>无自有产权住房</strong></li><li>连续足额缴存公积金满<strong>3个月</strong>（含）以上</li><li>本人或配偶在广州租房并实际居住</li></ul><h3 id="提取额度" tabindex="-1">提取额度 <a class="header-anchor" href="#提取额度" aria-label="Permalink to &quot;提取额度&quot;">​</a></h3><ul><li>每人每月最高提取额度按广州公积金中心公布的标准执行（一般为月租金或限额取低值）</li><li>具体限额建议查询广州住房公积金管理中心官网或公众号</li></ul><h3 id="线上办理流程" tabindex="-1">线上办理流程 <a class="header-anchor" href="#线上办理流程" aria-label="Permalink to &quot;线上办理流程&quot;">​</a></h3><ol><li>关注微信公众号**&quot;广州住房公积金&quot;<strong>，或下载</strong>广州住房公积金APP**</li><li>登录个人账户（首次需注册绑定）</li><li>选择**&quot;提取业务&quot;** → <strong>&quot;租房提取&quot;</strong></li><li>填写租赁信息，上传相关材料</li><li>提交申请，等待审核</li><li>审核通过后，资金自动转入绑定的银行卡</li></ol><div class="warning custom-block"><p class="custom-block-title">WARNING</p><p>租房提取一般按月或按季度自动划拨。首次办理需要提交材料审核，后续符合条件的会自动续期，不需要每次都申请。</p></div><h2 id="场景二-购房提取" tabindex="-1">场景二：购房提取 <a class="header-anchor" href="#场景二-购房提取" aria-label="Permalink to &quot;场景二：购房提取&quot;">​</a></h2><p>在广州或外地购买自住住房，可以提取公积金账户余额。</p><h3 id="申请条件-1" tabindex="-1">申请条件 <a class="header-anchor" href="#申请条件-1" aria-label="Permalink to &quot;申请条件&quot;">​</a></h3><ul><li>购买自住住房（新建商品房、二手房均可）</li><li>购房行为发生在规定时间范围内（一般为购房合同签订或房产证出证后一定期限内）</li></ul><h3 id="提取额度-1" tabindex="-1">提取额度 <a class="header-anchor" href="#提取额度-1" aria-label="Permalink to &quot;提取额度&quot;">​</a></h3><ul><li>不超过实际购房支出</li><li>一般可全额提取账户余额（不超过购房总价）</li></ul><h3 id="所需材料" tabindex="-1">所需材料 <a class="header-anchor" href="#所需材料" aria-label="Permalink to &quot;所需材料&quot;">​</a></h3><ul><li><strong>身份证</strong>原件</li><li><strong>购房合同</strong>或<strong>不动产权证</strong></li><li><strong>购房发票</strong>或<strong>契税完税证明</strong></li><li>配偶提取需提供<strong>结婚证</strong></li></ul><h3 id="购房提取-vs-还贷提取" tabindex="-1">购房提取 vs 还贷提取 <a class="header-anchor" href="#购房提取-vs-还贷提取" aria-label="Permalink to &quot;购房提取 vs 还贷提取&quot;">​</a></h3><ul><li><strong>购房提取</strong>：一次性提取，用于首付或补回首付支出</li><li><strong>还贷提取</strong>：按月/按年提取，用于偿还房贷本息</li></ul><p>两种可以分别办理，不冲突。</p><h2 id="场景三-离职-离开广州提取" tabindex="-1">场景三：离职/离开广州提取 <a class="header-anchor" href="#场景三-离职-离开广州提取" aria-label="Permalink to &quot;场景三：离职/离开广州提取&quot;">​</a></h2><p>从广州的单位离职后，公积金账户会被<strong>封存</strong>。满足条件后可以提取。</p><h3 id="提取条件" tabindex="-1">提取条件 <a class="header-anchor" href="#提取条件" aria-label="Permalink to &quot;提取条件&quot;">​</a></h3><ul><li>账户封存满<strong>半年</strong>（各地规定可能不同，以广州最新政策为准）</li><li>未在异地继续缴存公积金</li><li>部分情况支持销户提取（离开广州且不再回来工作）</li></ul><h3 id="办理方式" tabindex="-1">办理方式 <a class="header-anchor" href="#办理方式" aria-label="Permalink to &quot;办理方式&quot;">​</a></h3><ul><li><strong>线上</strong>：通过广州住房公积金APP或公众号提交申请</li><li><strong>线下</strong>：携带身份证到公积金服务网点办理</li></ul><div class="warning custom-block"><p class="custom-block-title">WARNING</p><p>离职提取不要急。如果短期内可能在广州找到新工作，建议不要提取，直接办理账户转移或启封续缴更方便。提取后重新开户缴存会有等待期。</p></div><h2 id="场景四-其他提取情形" tabindex="-1">场景四：其他提取情形 <a class="header-anchor" href="#场景四-其他提取情形" aria-label="Permalink to &quot;场景四：其他提取情形&quot;">​</a></h2><h3 id="退休提取" tabindex="-1">退休提取 <a class="header-anchor" href="#退休提取" aria-label="Permalink to &quot;退休提取&quot;">​</a></h3><p>达到法定退休年龄，可一次性提取账户全部余额并销户。携带退休证或退休审批表到公积金网点办理即可。</p><h3 id="大病提取" tabindex="-1">大病提取 <a class="header-anchor" href="#大病提取" aria-label="Permalink to &quot;大病提取&quot;">​</a></h3><p>职工本人或配偶、直系亲属患重大疾病，造成家庭生活严重困难的，可申请提取公积金。需提供医院诊断证明、医疗费用发票等材料。</p><h3 id="出境定居" tabindex="-1">出境定居 <a class="header-anchor" href="#出境定居" aria-label="Permalink to &quot;出境定居&quot;">​</a></h3><p>已注销国内户籍或取得境外永久居留权的，可申请销户提取。</p><h2 id="线上办理全流程" tabindex="-1">线上办理全流程 <a class="header-anchor" href="#线上办理全流程" aria-label="Permalink to &quot;线上办理全流程&quot;">​</a></h2><p>广州公积金提取越来越方便，大部分场景都可以线上办：</p><ol><li><strong>关注&quot;广州住房公积金&quot;微信公众号</strong>（或下载APP）</li><li><strong>注册登录</strong>：首次使用需要绑定个人信息和银行卡</li><li><strong>选择提取类型</strong>：根据你的情况选择对应的提取场景</li><li><strong>填写信息并上传材料</strong>：按页面提示操作</li><li><strong>提交审核</strong>：一般1-3个工作日出结果</li><li><strong>到账</strong>：审核通过后资金转入绑定银行卡</li></ol><p>也可以通过**&quot;粤省事&quot;**小程序 → 搜索&quot;公积金&quot;进入办理。</p><h2 id="避坑提醒" tabindex="-1">避坑提醒 <a class="header-anchor" href="#避坑提醒" aria-label="Permalink to &quot;避坑提醒&quot;">​</a></h2><ul><li><strong>租房提取有额度上限</strong>：不是交多少租就能提多少，超出限额部分不能提</li><li><strong>不要找中介代提</strong>：市面上有&quot;代提公积金&quot;的中介，通过伪造材料提取属于违法行为，一旦查实会被列入黑名单、追回资金，严重的追究法律责任</li><li><strong>提取有间隔限制</strong>：部分提取类型有时间间隔要求（如租房提取一般按月/季度），不能随时提</li><li><strong>配偶也可以提取</strong>：夫妻双方都有公积金的，可以分别按各自条件提取</li><li><strong>异地购房提取</strong>：在广州缴存的公积金，在外地购房也可以提取，但材料要求和流程可能不同，建议提前咨询</li><li><strong>提取后影响贷款额度</strong>：如果近期有公积金贷款买房的计划，提取公积金会减少贷款额度，提前做好规划</li></ul><p>公积金是咱们自己的钱，该提就提，但一定要走正规渠道。</p>',45)])])}]]);export{o as __pageData,i as default};
